nation), Is.EqualTo(789));            Assert.That(EzAnalysisSchemaManager.TryGetMeta(destination, EzAnalysisSchemaManager.META_KEY_SCHEMA_VERSION),                Is.EqualTo(EzAnalysisSchemaManager.MAIN_SCHEMA_VERSION.ToString(CultureInfo.InvariantCulture)));            Assert.That(EzAnalysisSchemaManager.TryGetMeta(destination, EzAnalysisSchemaManager.META_KEY_ANALYSIS_VERSION),                Is.EqualTo(EzAnalysisPersistentStore.ANALYSIS_VERSION.ToString(CultureInfo.InvariantCulture)));            Assert.That(hasColumn(destination, EzAnalysisSchemaManager.TABLE_ENTRY, EzAnalysisSchemaManager.COL_PP), Is.False);            Assert.That(hasColumn(destination, EzAnalysisSchemaManager.TABLE_ENTRY, EzAnalysisSchemaManager.COL_TAG_UPDATED_AT), Is.False);            Assert.That(hasColumn(destination, EzAnalysisSchemaManager.TABLE_MANIA, EzAnalysisSchemaManager.COL_XXY_SR), Is.False);        }        private static void createLegacyV6Database(SqliteConnection connection)        {            EzAnalysisSchemaManager.EnsureMetaTableExists(connection);            using var create = connection.CreateCommand();            create.CommandText = $@"CREATE TABLE {EzAnalysisSchemaManager.TABLE_ENTRY} (    {EzAnalysisSchemaManager.COL_BEATMAP_ID} TEXT PRIMARY KEY,    {EzAnalysisSchemaManager.COL_BEATMAP_HASH} TEXT NOT NULL,    {EzAnalysisSchemaManager.COL_BEATMAP_MD5} TEXT NOT NULL,    {EzAnalysisSchemaManager.COL_RULESET_ONLINE_ID} INTEGER NOT NULL,    {EzAnalysisSchemaManager.COL_COMMON_UPDATED_AT} INTEGER NOT NULL DEFAULT 0,    {EzAnalysisSchemaManager.COL_AVERAGE_KPS} REAL NOT NULL DEFAULT 0,    {EzAnalysisSchemaManager.COL_MAX_KPS} REAL NOT NULL DEFAULT 0,    {EzAnalysisSchemaManager.COL_KPS_LIST_JSON} TEXT NOT NULL DEFAULT '[]',    {EzAnalysisSchemaManager.COL_PP} REAL NULL,    {EzAnalysisSchemaManager.COL_TAG_UPDATED_AT} INTEGER NOT NULL DEFAULT 0,    {EzAnalysisSchemaManager.COL_TAG_PAYLOAD_JSON} TEXT NOT NULL DEFAULT '');CREATE TABLE {EzAnalysisSchemaManager.TABLE_MANIA} (    {EzAnalysisSchemaManager.COL_BEATMAP_ID} TEXT PRIMARY KEY,    {EzAnalysisSchemaManager.COL_UPDATED_AT} INTEGER NOT NULL DEFAULT 0,    {EzAnalysisSchemaManager.COL_XXY_SR} REAL NULL,    {EzAnalysisSchemaManager.COL_COLUMN_COUNTS_JSON} TEXT NOT NULL DEFAULT '{{}}',    {EzAnalysisSchemaManager.COL_HOLD_NOTE_COUNTS_JSON} TEXT NOT NULL DEFAULT '{{}}');";            create.ExecuteNonQuery();            EzAnalysisSchemaManager.SetMeta(connection, EzAnalysisSchemaManager.META_KEY_SCHEMA_VERSION, "2");            EzAnalysisSchemaManager.SetMeta(connection, EzAnalysisSchemaManager.META_KEY_ANALYSIS_VERSION, "6");        }        private static void insertSampleRow(SqliteConnection connection, long commonUpdatedAt, long maniaUpdatedAt)        {            using var cmd = connection.CreateCommand();            cmd.CommandText = $@"INSERT INTO {EzAnalysisSchemaManager.TABLE_ENTRY}(    {EzAnalysisSchemaManager.COL_BEATMAP_ID},    {EzAnalysisSchemaManager.COL_BEATMAP_HASH},    {EzAnalysisSchemaManager.COL_BEATMAP_MD5},    {EzAnalysisSchemaManager.COL_RULESET_ONLINE_ID},    {EzAnalysisSchemaManager.COL_COMMON_UPDATED_AT},    {EzAnalysisSchemaManager.COL_AVERAGE_KPS},    {EzAnalysisSchemaManager.COL_MAX_KPS},    {EzAnalysisSchemaManager.COL_KPS_LIST_JSON}) VALUES (    '00000000-0000-0000-0000-000000000001',    'hash',    'md5',    3,    $commonUpdatedAt,    1,    2,    '[]');INSERT INTO {EzAnalysisSchemaManager.TABLE_MANIA}(    {EzAnalysisSchemaManager.COL_BEATMAP_ID},    {EzAnalysisSchemaManager.COL_UPDATED_AT},    {EzAnalysisSchemaManager.COL_COLUMN_COUNTS_JSON},    {EzAnalysisSchemaManager.COL_HOLD_NOTE_COUNTS_JSON}) VALUES (    '00000000-0000-0000-0000-000000000001',    $maniaUpdatedAt,    '{{}}',    '{{}}');";            cmd.Parameters.AddWithValue("$commonUpdatedAt", commonUpdatedAt);            cmd.Parameters.AddWithValue("$maniaUpdatedAt", maniaUpdatedAt);            cmd.ExecuteNonQuery();        }        private static long readCommonUpdatedAt(SqliteConnection connection)        {            using var cmd = connection.CreateCommand();            cmd.CommandText = $"SELECT {EzAnalysisSchemaManager.COL_COMMON_UPDATED_AT} FROM {EzAnalysisSchemaManager.TABLE_ENTRY} LIMIT 1;";            return (long)(cmd.ExecuteScalar() ?? 0L);        }        private static long readManiaUpdatedAt(SqliteConnection connection)        {            using var cmd = connection.CreateCommand();            cmd.CommandText = $"SELECT {EzAnalysisSchemaManager.COL_UPDATED_AT} FROM {EzAnalysisSchemaManager.TABLE_MANIA} LIMIT 1;";            return (long)(cmd.ExecuteScalar() ?? 0L);        }        private static bool hasColumn(SqliteConnection connection, string tableName, string columnName)        {            using var cmd = connection.CreateCommand();            cmd.CommandText = $"PRAGMA table_info({tableName});";            using var reader = cmd.ExecuteReader();            while (reader.Read())            {                if (string.Equals(reader.GetString(1), columnName, StringComparison.OrdinalIgnoreCase))                    return true;            }            return false;        }    }}